pub fn _3asub(cpu: &mut Cpu) {
    'b11: {
        'b10: {
            'b8: {
                cpu.reg.a = 0xff;
                cpu.flags.z = cpu.reg.a == 0;
                cpu.flags.n = (cpu.reg.a >> 7) != 0;
                cpu.mem[sym::FCharIndex] = cpu.reg.a;
                cpu.reg.a = cpu.mem[sym::CharPosn];
                cpu.flags.z = cpu.reg.a == 0;
                cpu.flags.n = (cpu.reg.a >> 7) != 0;
                if cpu.reg.a != 0xb9 {
                    if cpu.reg.a == 0xb1 {
                        cpu.reg.a = 0xfb;  // impaled
                        cpu.flags.z = cpu.reg.a == 0;
                        cpu.flags.n = (cpu.reg.a >> 7) != 0;
                        if cpu.reg.a != 0x00 {
                            break 'b11;
                        } else {
                            break 'b10;
                        }
                    } else {
                        if cpu.reg.a >= 0x6a {
                            if cpu.reg.a < 0x6f {
                                break 'b8;
                            }
                        }
                        if cpu.reg.a == 0xb2 {
                            return;
                        }
                        cpu.reg.a = 0xf1;
                        cpu.flags.z = cpu.reg.a == 0;
                        cpu.flags.n = (cpu.reg.a >> 7) != 0;
                        cpu.reg.x = cpu.mem[sym::CharID];
                        cpu.flags.z = cpu.reg.x == 0;
                        cpu.flags.n = (cpu.reg.x >> 7) != 0;
                        if cpu.reg.x != 0x00 {
                            cpu.reg.a = 0xf5;  // kid strikes lower than opponent
                            cpu.flags.z = cpu.reg.a == 0;
                            cpu.flags.n = (cpu.reg.a >> 7) != 0;
                        }
                        cpu.flags.c = false;
                        let _r = (cpu.reg.a as u16) + cpu.mem[sym::FCharY] as u16 + (cpu.flags.c as u16);
                        cpu.reg.a = _r as u8;
                        cpu.flags.c = (_r >> 8) != 0;
                        cpu.flags.z = cpu.reg.a == 0;
                        cpu.flags.n = (cpu.reg.a >> 7) != 0;
                        cpu.mem[sym::FCharY] = cpu.reg.a;
                        break 'b10;
                    }
                }
            }
            cpu.reg.a = 0x04;
            cpu.flags.z = cpu.reg.a == 0;
            cpu.flags.n = (cpu.reg.a >> 7) != 0;
            cpu.flags.c = false;
            let _r = (cpu.reg.a as u16) + cpu.mem[sym::FCharY] as u16 + (cpu.flags.c as u16);
            cpu.reg.a = _r as u8;
            cpu.flags.c = (_r >> 8) != 0;
            cpu.flags.z = cpu.reg.a == 0;
            cpu.flags.n = (cpu.reg.a >> 7) != 0;
            cpu.mem[sym::FCharY] = cpu.reg.a;
        }
        cpu.reg.a = 0x05;
        cpu.flags.z = cpu.reg.a == 0;
        cpu.flags.n = (cpu.reg.a >> 7) != 0;
    }
    crate::ext::addfcharx(cpu);
    cpu.reg.a = cpu.mem[sym::CharID];
    cpu.flags.z = cpu.reg.a == 0;
    cpu.flags.n = (cpu.reg.a >> 7) != 0;
    if cpu.reg.a != 0x00 {
        cpu.reg.a = 0x01;  // opponents: 1
        cpu.flags.z = cpu.reg.a == 0;
        cpu.flags.n = (cpu.reg.a >> 7) != 0;
    }
    cpu.reg.a ^= cpu.mem[sym::FCharX];
    cpu.reg.a ^= cpu.mem[sym::FCharFace];
    cpu.reg.a &= 0x01;
    if cpu.reg.a == 0x00 {
        let _v = cpu.mem[sym::FCharX].wrapping_add(1);
        cpu.mem[sym::FCharX] = _v;
        cpu.flags.z = _v == 0;
        cpu.flags.n = (_v >> 7) != 0;
        if cpu.flags.z {
            let _v = cpu.mem[sym::FCharX + 1].wrapping_add(1);
            cpu.mem[sym::FCharX + 1] = _v;
            cpu.flags.z = _v == 0;
            cpu.flags.n = (_v >> 7) != 0;
        }
    }
    cpu.mem[sym::FCharImage] = 0x41;
    cpu.mem[sym::FCharTable] = 0x00;
    cpu.mem[sym::FCharCU] = 0x00;
    cpu.mem[sym::FCharCL] = 0x00;
    cpu.mem[sym::FCharCR] = 0x28;
    cpu.mem[sym::FCharCD] = 0xc0;
    cpu.reg.a = 0x05;
    cpu.flags.z = cpu.reg.a == 0;
    cpu.flags.n = (cpu.reg.a >> 7) != 0;
    crate::ext::addcharobj(cpu);
    return;
}
